mapper.select:

SELECT * FROM (
    SELECT /*+ INDEX_DESC(tbl_board pk_board) */ 
        rownum rn, b.bno, b.title, b.content, b.writer, b.regdate, b.updatedate,
        m.user_img, c.cat_name
    FROM tbl_board b
    LEFT JOIN tbl_member m ON b.writer = m.userid
    LEFT JOIN tbl_category c ON b.cat_id = c.cat_id
    WHERE 1=1



    AND rownum <= #{cri.pageNum} * #{amount}
) WHERE rn > (#{cri.pageNum} - 1) * #{amount}

SELECT * FROM ( SELECT b.bno, b.title, b.content, b.writer, b.regdate, b.replycnt, b.likecnt, b.dislikecnt, c.cat_name, c.cat_slug FROM tbl_board b LEFT JOIN tbl_category c ON b.cat_id = c.cat_id
AND c.cat_name = #{category}
ORDER BY b.bno DESC ) WHERE ROWNUM <= 20

SELECT count(*) FROM tbl_board


		cat_id = #{category}




				AND cat_id IN ('tech', 'career', 'etc')
